'use strict'

const assert = require('node:assert/strict')
const http2 = require('node:http2')
const { once } = require('node:events')
const { H2CClient } = require('/workspace/undici')

async function runCase (name, requestHeaders, expectedHeaders, expectedRawCookieValues) {
  let observedHeaders
  let observedRawHeaders
  const server = http2.createServer()
  server.on('stream', (stream, headers, _flags, rawHeaders) => {
    observedHeaders = headers
    observedRawHeaders = rawHeaders
    stream.respond({ ':status': 200 })
    stream.end('ok')
  })

  server.listen(0)
  await once(server, 'listening')

  const client = new H2CClient(`http://localhost:${server.address().port}`)
  try {
    const response = await client.request({ path: '/', method: 'GET', headers: requestHeaders })
    await response.body.text()
  } finally {
    await client.close()
    server.close()
    await once(server, 'close')
  }

  for (const [key, expected] of Object.entries(expectedHeaders)) {
    assert.equal(observedHeaders[key], expected, `${name}: ${key}`)
  }

  if (expectedRawCookieValues) {
    const actualRawCookieValues = []
    for (let i = 0; i < observedRawHeaders.length; i += 2) {
      if (observedRawHeaders[i] === 'cookie') actualRawCookieValues.push(observedRawHeaders[i + 1])
    }
    assert.deepEqual(actualRawCookieValues, expectedRawCookieValues, `${name}: raw cookie fields`)
  }

  console.log(`${name}: ok`)
}

async function main () {
  await runCase(
    'object cookie array uses semicolons and split fields',
    { cookie: ['a=b', 'c=d', 'e=f'] },
    { cookie: 'a=b; c=d; e=f' },
    ['a=b', 'c=d', 'e=f']
  )

  await runCase(
    'header tuple duplicate cookie values use semicolons',
    ['cookie', 'a=b', 'cookie', 'c=d'],
    { cookie: 'a=b; c=d' },
    ['a=b', 'c=d']
  )

  await runCase(
    'uppercase Cookie still treated as cookie',
    { Cookie: ['a=b', 'c=d'] },
    { cookie: 'a=b; c=d' },
    ['a=b', 'c=d']
  )

  await runCase(
    'non-cookie repeated headers still use commas',
    { 'x-test': ['one', 'two'] },
    { 'x-test': 'one, two' }
  )
}

main().catch(err => {
  console.error(err)
  process.exitCode = 1
})
